@media (max-width: 480px) {
    #game-container {
        width: 320px;
        height: 520px;
    }
    button {
        font-size: 14px;
        padding: 10px 18px;
    }
    #score, #history {
        font-size: 14px;
        padding: 6px 12px;
    }
    #welcome-screen h1 {
        font-size: 2.2rem;
    }
    #welcome-screen p {
        font-size: 1rem;
