    if (e.code === 'Space') {
        e.preventDefault();
        if (gameRunning) {
            if (gamePaused) {
                pauseGame();
            } else {
                bird.velocity = bird.jumpStrength;
            }
        } else {
            startGame();
        }
    }
});

// Touch controls for mobile
canvas.addEventListener('touchstart', () => {
    if (gameRunning) {
        if (gamePaused) {
            pauseGame();
        } else {
            bird.velocity = bird.jumpStrength;
        }
    } else {
        startGame();
    }
});

