        --border-radius: 25px;
        --box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
        --blur: blur(8px);
        --transition: all 0.3s ease;
    }

    .flex-center {
        display: flex;
        justify-content: center;
        align-items: center;
    }

    .text-shadow {
        text-shadow: var(--text-shadow);
    }

    .no-select {
        user-select: none;
    }
}

@layer components {
    /* Game Container */
    #game-container {
        position: relative;
        width: 380px;
        height: 600px;
        overflow: hidden;
        border: 2px solid rgba(255, 255, 255, 0.3);
        border-radius: 12px;
        box-shadow: var(--box-shadow);
        background-color: var(--bg-color);
        backdrop-filter: var(--blur);
        transition: var(--transition);
    }

    #game-canvas {
        display: block;
        width: 100%;
        height: 100%;
    }

